import { useCallback } from 'react';

import { TooltipItem, SeriesDisplayMode } from '../../../../types/tooltip.js';
import { VirtualEstimatedSize } from '../types/virtual-estimated-size.js';

const SINGLE_DIMENSION_ESTIMATED_ITEM_HEIGHT_PX = 25;
const MULTIPLE_DIMENSION_ESTIMATED_ITEM_HEIGHT_PX = 21.5;

export const useSeriesBasedItemEstimatedSize = (
  items: TooltipItem[],
  displayMode: SeriesDisplayMode,
): VirtualEstimatedSize =>
  useCallback(
    (itemIndex) => {
      const { name } = items[itemIndex];
      const isOneLine =
        typeof name === 'string' ||
        name.length === 1 ||
        displayMode === 'single-line';

      return isOneLine
        ? SINGLE_DIMENSION_ESTIMATED_ITEM_HEIGHT_PX
        : name.length * MULTIPLE_DIMENSION_ESTIMATED_ITEM_HEIGHT_PX;
    },
    [items, displayMode],
  );
